for i in 0..N-1:
    if i == 0:
        A[0].data = H("PoSME-init-v1" || s || I2OSP(0, 4))
    else:
        A[i].data = H("PoSME-init-v1" || s || I2OSP(i, 4)
                      || A[i-1].data
                      || A[floor(i/2)].data)
    A[i].causal = H("PoSME-causal-v1" || s || I2OSP(i, 4))

root_0 = MerkleRoot(A)
T_0 = H("PoSME-transcript-v1" || s || root_0)

STEP(t):
    cursor = T_{t-1}

    // 1. Determine Target Bank
    bank_id = XOF(cursor, 0) mod params.B_banks

    // Start high-resolution cycle counter
    t_start = RDTSC() 

    // 2. Intra-Step Bank Collision Reads
    addrs = []
    for j in 0..d-1:
        // Generate pseudo-random address
        raw_a = XOF(cursor, j + 1) mod params.N

        // Mutate raw_a to ensure it maps to bank_id
        a = force_bank_mapping(raw_a, bank_id, params)
        addrs.append(a)

        val = A[a]
        cursor = H(cursor || val.data || val.causal)

    // 3. Write with Spatial Neighborhood Entanglement
    raw_w = XOF(cursor, d + 1) mod params.N
    w = force_bank_mapping(raw_w, bank_id, params)
    old = A[w]

    // Incorporate causal hashes of logical neighbors
    n_prev = A[(w - 1) mod params.N].causal
    n_next = A[(w + 1) mod params.N].causal

    new_data = H(old.data || cursor || old.causal 
                  || n_prev || n_next)
    new_causal = H(old.causal || cursor || I2OSP(t, 4) 
                    || n_prev || n_next)
    A[w] = {data: new_data, causal: new_causal}

    // Stop cycle counter to capture physical latency jitter
    t_end = RDTSC()
    delta_t = t_end - t_start

    // 4. Update Commitments
    root_t = MerkleUpdate(root_{t-1}, w, A[w])
    T_t = H(T_{t-1} || I2OSP(t, 4) || cursor
            || root_t || I2OSP(delta_t, 8))

    // 5. Log step for Prover transcript
    log[t] = {addrs, w, old, A[w], cursor, root_t, delta_t}

PROVE(K, Q, R_depth): C_roots = MerkleRoot([root_0, ..., root_K]) challenges = FS(T_K, C_roots, Q) proof = {params, T_K, C_roots, step_proofs: []}
for c in challenges: sp = make_step_proof(c, R_depth) proof.step_proofs.append(sp) return proof
make_step_proof(step, depth): sp = { step_id: step, cursor_in: T_{step-1}, cursor_out: log[step].cursor, root_before: root_{step-1}, root_after: log[step].root_t, root_chain_paths: [ MerklePath(C_roots, step-1), MerklePath(C_roots, step) ], reads: [], write: {addr: w, old: log[step].old, new: A[w], merkle_path: MerklePath(root_{step-1}, w), neighbor_prev: { addr: (w-1) mod N, block: A[(w-1) mod N], merkle_path: MerklePath(root_{step-1}, (w-1) mod N)}, neighbor_next: { addr: (w+1) mod N, block: A[(w+1) mod N], merkle_path: MerklePath(root_{step-1}, (w+1) mod N)}}, writers: [] } for j in 0..d-1: sp.reads.append({ addr, block, merkle_path: MerklePath(root_{step-1}, addr)}) if depth > 0: ws = last_writer(addr, step) if ws == 0: sp.writers.append({type: "init", init_path: MerklePath(root_0, addr)}) else: sp.writers.append({type: "step", proof: make_step_proof(ws, depth-1)}) else: sp.writers.append({type: "leaf", writer_step: last_writer(addr, step), merkle_path: MerklePath( root_{ws}, addr)}) return sp

VERIFY(seed, params, T_K, C_roots, proof): // 1. Trusted anchor root_0 = compute_init_root(seed, params.N) T_0 = H("PoSME-transcript-v1" || seed || root_0)
// 2. Verify root_0 in root chain assert MerkleVerify(C_roots, 0, root_0, proof.root_0_path)
// 3. Recompute challenges challenges = FS(T_K, C_roots, params.Q)
// 4. Verify each challenged step for sp in proof.step_proofs: verify_step(sp, C_roots, root_0, params)
verify_step(sp, C_roots, root_0, params): // A. Verify roots are in the root chain assert MerkleVerify(C_roots, sp.step_id - 1, sp.root_before, sp.root_chain_paths[0]) assert MerkleVerify(C_roots, sp.step_id, sp.root_after, sp.root_chain_paths[1])
// B. Verify read Merkle proofs for j in 0..d-1: assert MerkleVerify(sp.root_before, sp.reads[j].addr, sp.reads[j].block, sp.reads[j].merkle_path)
// C. Replay pointer-chase cursor = sp.cursor_in for j in 0..d-1: a = XOF(cursor, j) mod N assert a == sp.reads[j].addr cursor = H(cursor || sp.reads[j].block.data || sp.reads[j].block.causal)
// D. Verify write with spatial neighbors w = XOF(cursor, d) mod N assert w == sp.write.addr assert MerkleVerify(sp.root_before, w, sp.write.old, sp.write.merkle_path)
// D1. Verify spatial neighbor Merkle proofs w_prev = (w - 1) mod N w_next = (w + 1) mod N np = sp.write.neighbor_prev nn = sp.write.neighbor_next assert np.addr == w_prev assert nn.addr == w_next assert MerkleVerify(sp.root_before, w_prev, np.block, np.merkle_path) assert MerkleVerify(sp.root_before, w_next, nn.block, nn.merkle_path) n_prev = np.block.causal n_next = nn.block.causal
// D2. Verify symbiotic write with spatial entanglement assert sp.write.new.data == H(sp.write.old.data || cursor || sp.write.old.causal || n_prev || n_next) assert sp.write.new.causal == H(sp.write.old.causal || cursor || I2OSP(sp.step_id, 4) || n_prev || n_next)
// E. Verify Merkle root update assert sp.root_after == MerkleUpdate( sp.root_before, w, sp.write.new)
// F. Compute and store transcript value for cross-check T_c = H(sp.cursor_in || I2OSP(sp.step_id, 4) || cursor || sp.root_after) // If another challenged step c' has cursor_in == T_c, // verify they match. If sp.step_id == K, verify // T_c == T_K (the public final transcript). stored_transcripts[sp.step_id] = T_c
// G. Recursive causal provenance for j in 0..d-1: verify_writer(sp.writers[j], sp.reads[j], C_roots, root_0, params)

posme-proof = { 1 => posme-params, 2 => bstr .size 32, ; final-transcript (T_K) 3 => bstr .size 32, ; root-chain-commitment 4 => [+ step-proof], ; challenged-steps }
posme-params = { 1 => uint, ; arena-blocks (N) 2 => uint, ; total-steps (K) 3 => uint, ; reads-per-step (d) 4 => uint, ; challenges (Q) 5 => uint, ; recursion-depth (R) 6 => uint, ; bank-count (B) }
step-proof = { 1 => uint, ; step-id 2 => bstr .size 32, ; cursor-in 3 => bstr .size 32, ; cursor-out 4 => bstr .size 32, ; root-before 5 => bstr .size 32, ; root-after 6 => [+ bstr .size 32], ; root-chain-paths 7 => [+ read-witness], ; reads 8 => write-witness, ; write 9 => [* writer-proof], ; recursive provenance 10 => uint, ; timing-entropy (delta_t) }
read-witness = { 1 => uint, ; address 2 => bstr .size 32, ; data 3 => bstr .size 32, ; causal-hash 4 => [+ bstr .size 32], ; merkle-path }
write-witness = { 1 => uint, ; address 2 => bstr .size 32, ; old-data 3 => bstr .size 32, ; old-causal 4 => bstr .size 32, ; new-data 5 => bstr .size 32, ; new-causal 6 => [+ bstr .size 32], ; merkle-path 7 => read-witness, ; neighbor-prev (w-1) 8 => read-witness, ; neighbor-next (w+1) }
writer-proof = { 1 => uint, ; type (0=init, 1=step, 2=leaf) ? 2 => uint, ; writer-step-id ? 3 => step-proof, ; recursive step proof ? 4 => [+ bstr .size 32], ; merkle-path }

